package operators;


public class RelationalOperators {
	
	static int a = 10;
	static int b = 20;

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		System.out.println(a > b);
		System.out.println(a < b);
		System.out.println(a != b);
		System.out.println(a >= b);
		System.out.println(a <= b);
		System.out.println(a == b);
		

	}

}
